def _cassandra_table_to_nested(cassandra_table: CassandraTable) -> CassandraTableNested:
    """Convert flat CassandraTable to nested format."""
    attrs = CassandraTableAttributes()
    _populate_cassandra_table_attrs(attrs, cassandra_table)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        cassandra_table,
        _CASSANDRA_TABLE_REL_FIELDS,
        CassandraTableRelationshipAttributes,
    )
    return CassandraTableNested(
        guid=cassandra_table.guid,
        type_name=cassandra_table.type_name,
        status=cassandra_table.status,
        version=cassandra_table.version,
        create_time=cassandra_table.create_time,
        update_time=cassandra_table.update_time,
        created_by=cassandra_table.created_by,
        updated_by=cassandra_table.updated_by,
        classifications=cassandra_table.classifications,
        classification_names=cassandra_table.classification_names,
        meanings=cassandra_table.meanings,
        labels=cassandra_table.labels,
        business_attributes=cassandra_table.business_attributes,
        custom_attributes=cassandra_table.custom_attributes,
        pending_tasks=cassandra_table.pending_tasks,
        proxy=cassandra_table.proxy,
        is_incomplete=cassandra_table.is_incomplete,
        provenance_type=cassandra_table.provenance_type,
        home_id=cassandra_table.home_id,
        depth=cassandra_table.depth,
        immediate_upstream=cassandra_table.immediate_upstream,
        immediate_downstream=cassandra_table.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _cassandra_table_from_nested(nested: CassandraTableNested) -> CassandraTable:
    """Convert nested format to flat CassandraTable."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else CassandraTableAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _CASSANDRA_TABLE_REL_FIELDS,
        CassandraTableRelationshipAttributes,
    )
    return CassandraTable(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_cassandra_table_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _cassandra_table_to_nested_bytes(
    cassandra_table: CassandraTable, serde: Serde
) -> bytes:
    """Convert flat CassandraTable to nested JSON bytes."""
    return serde.encode(_cassandra_table_to_nested(cassandra_table))


def _cassandra_table_from_nested_bytes(data: bytes, serde: Serde) -> CassandraTable:
    """Convert nested JSON bytes to flat CassandraTable."""
    nested = serde.decode(data, CassandraTableNested)
    return _cassandra_table_from_nested(nested)


